var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>타나베린의, 그리고 그로니아의 전 병력에게 전파합니다.</color>","JPN":"<color=#ffd34c>タナベリンの、そしてグロニアの全兵力に伝えます。</color>","ENG":"<color=#ffd34c>To all the forces of Tanaberin and Gronia.</color>","TWN":"<color=#ffd34c>達那貝林，還有格羅尼亞的全體士兵。</color>"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>제 이름은, 크리스티나 브레히트입니다.</color>","JPN":"<color=#ffd34c>私の名前はクリスティーナ・ブレヒトです。</color>","ENG":"<color=#ffd34c>My name is Christina Brecht.</color>","TWN":"<color=#ffd34c>我叫克莉絲蒂娜·布萊希特。</color>"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>여러분에게는 무공 훈장을 받은 꼬마로 더 잘 알려져 있겠죠.</color>","JPN":"<color=#ffd34c>皆さんには勲章を受賞したチビと言った方がわかりやすいかもしれません。</color>","ENG":"<color=#ffd34c>You probably know me better as the kid who received the Medal of Honor.</color>","TWN":"<color=#ffd34c>沒錯…就是那個授勳的小鬼。</color>"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_NULL","text":{"KOREA":"이 무전기에서 나오는 목소리… 정말 브레히트 중사야?","JPN":"この無線機からの声……本当にブレヒト軍曹なのか？","ENG":"The voice coming from the radio... Is that really Sergeant Brecht?","TWN":"這個對講機裡的聲音……是布萊希特中士？"},"stage":{"bg":"GRONIA_STREET","slots":{"L":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_NULL","text":{"KOREA":"나, 나 인터뷰 들어 본 적 있어. 본인이 분명해.","JPN":"お、俺、インタビュー聞いたことあるぞ。本人で間違いない。","ENG":"I-I've heard her interviews. It's definitely her.","TWN":"我…我聽過她的採訪，確實是她本人。"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CITIZEN_EXTRA_NULL_NULL","text":{"KOREA":"브레히트라면, 지난번 전당에서……?","JPN":"ブレヒトというと、この前の建国記念館の……？","ENG":"Brecht? You mean that girl at the hall...?","TWN":"布萊希特，是之前那個……？"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CITIZEN_EXTRA_NULL_NULL","text":{"KOREA":"그 애야, 그 애. 무공 훈장 받은 소년병.","JPN":"あの子だ、あの子。勲章を授与された少年兵。","ENG":"That's her, yeah. The child soldier who received the Medal of Honor.","TWN":"就是她，獲得授勳的年輕士兵。"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재, 타나베린은 5종 침식체에게 공격 받고 있습니다.</color>","JPN":"<color=#ffd34c>現在、タナベリンは第5種侵食体から攻撃されています。</color>","ENG":"<color=#ffd34c>As of now, Tanaberin is under attack by a Category 5 C.O.</color>","TWN":"<color=#ffd34c>目前，達那貝林正在遭受5類侵蝕體的攻擊。</color>"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>여러분이 받은 이해할 수 없는 명령 말이에요.</color>","JPN":"<color=#ffd34c>皆さんが受けた、理解に苦しむ命令のことなんですが。</color>","ENG":"<color=#ffd34c>I know you received a strange order that you don't understand.</color>","TWN":"<color=#ffd34c>大家也有收到讓人無法理解的命令。</color>"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_NULL","text":{"KOREA":"확인 결과, 정규 회선을 통한 무전이라고 합니다.","JPN":"確認の結果、定期回線からの無線とのことです。","ENG":"Analysis shows that comms are coming from the proper channels.","TWN":"是透過正規線路播出的。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLDIER_GRONIA_NULL_NULL","text":{"KOREA":"지금 바로 차단할 수 있습니다. 어떻게 하시겠습니까?","JPN":"今すぐにでも遮断できますが、いかがなさいますか？","ENG":"I could block it if you want, sir. What are your orders?","TWN":"現在就可以切斷，請問要怎麼做？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"SOLDIER_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"아니. 더 들어 보세나.","JPN":"いや。もう少し聞いてみよう。","ENG":"No. Let's hear what she has to say.","TWN":"不，再聽聽。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>제 말을 믿기 어려울 거라는 건 제가 제일 잘 알아요.</color>","JPN":"<color=#ffd34c>私の言葉を信じるのが簡単でないことは、私が誰よりもわかっています。</color>","ENG":"<color=#ffd34c>I'm well aware that you find it difficult to believe what I'm saying.</color>","TWN":"<color=#ffd34c>我知道我說的這些話很難讓人相信。</color>"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>하지만… 여러분이 그렇게 추켜세워 주던 무공 훈장 수훈자로서.</color>","JPN":"<color=#ffd34c>ですが……皆さんに褒め称えていただいた勲章の受賞者として。</color>","ENG":"<color=#ffd34c>But... as the war hero that all of you put on a pedestal.</color>","TWN":"<color=#ffd34c>但是……我作為被各位推舉的授勳者，</color>"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>부탁드립니다.</color>","JPN":"<color=#ffd34c>お願いします。</color>","ENG":"<color=#ffd34c>I ask you.</color>","TWN":"<color=#ffd34c>拜託大家。</color>"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>조금만… 아주 조금만이라도 괜찮으니까.</color>","JPN":"<color=#ffd34c>少し……ほんの少しでいいので。</color>","ENG":"<color=#ffd34c>Please... Just a little while is fine.</color>","TWN":"<color=#ffd34c>請大家稍微……哪怕一點嚇也可以。</color>"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};